//--Statistics Help
$pgv_lang["help_statisticsplot.php"] = "~GrĂĄfico estatĂ­stico~<br /><br />Esta ĂŠ a pĂĄgina de resultados, mostrando o grĂĄfico das estatĂ­sticas de seu banco de dados, conforme definido pelas entradas na pĂĄgina anterior.";
$pgv_lang["help_statistics.php"] = "~GrĂĄfico estatĂ­stico~<br /><br />Esta pĂĄgina permite determinar os critĂŠrios para produzir uma exibiĂ§ĂŁo grĂĄfica de vĂĄrias estatĂ­sticas de seu banco de dados.";
$pgv_lang["stat_help"]			= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />VĂĄrios grĂĄficos diferentes de estatĂ­sticas de seu banco de dados podem ser produzidos.<br /><br />Selecione o grĂĄfico e, em seguida, ajuste as opĂ§Ăľes nas caixas.<br /><br />Os nĂşmeros incluĂ­dos em cada grĂĄfico dependem de os dados disponĂ­veis. Por exemplo, indivĂ­duos sem um mĂŞs de nascimento (por exemplo, apenas '1856') nĂŁo podem ser incluĂ­dos em um grĂĄfico de nascimentos por mĂŞs.";
$pgv_lang["stat_help_x"]			= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~EIXO X~<br /><br />As seguintes opĂ§Ăľes estĂŁo disponĂ­veis para o eixo X (horizontal). Cada um serĂĄ entĂŁo apresentado de acordo com as opĂ§Ăľes definidas para os eixos Y e Z.<p style=\"padding-left: 25px\"><b>#pgv_lang[stat_11_mb]#</b>&nbsp;&nbsp;pessoas nascidas em cada mĂŞs.<br /><b>#pgv_lang[stat_12_md]#</b>&nbsp;&nbsp;pessoas que morreram em cada mĂŞs.<br /><b>#pgv_lang[stat_13_mm]#</b>&nbsp;&nbsp;casamentos que ocorreram em cada mĂŞs.<br /><b>#pgv_lang[stat_14_mb1]#</b>&nbsp;&nbsp;o nĂşmero de primogĂŞnitos para cada famĂ­lia por mĂŞs.<br /><b>#pgv_lang[stat_15_mm1]#</b>&nbsp;&nbsp;o nĂşmero de primeiros casamentos por mĂŞs.<br /><b>#pgv_lang[stat_16_mmb]#</b>&nbsp;&nbsp;o nĂşmero de meses entre o casamento e o nascimento do primeiro filho desse casal.<br /><b>#pgv_lang[stat_17_arb]#</b>&nbsp;&nbsp;amorte, relacionado ao perĂ­odo de tempo que inclui o ano de nascimento de cada pessoa.<br /><b>#pgv_lang[stat_18_ard]#</b>&nbsp;&nbsp;idade na morte, relacionada ao perĂ­odo de tempo que inclui o ano da morte de cada pessoa.<br /><b>#pgv_lang[stat_19_arm]#</b>&nbsp;&nbsp;idade mĂŠdia das pessoas no momento de seus casamentos<br /><b>#pgv_lang[stat_20_arm1]#</b>&nbsp;&nbsp;idade mĂŠdia das pessoas no momento do primeiro casamento.<br /><b>#pgv_lang[stat_21_nok]#</b>&nbsp;&nbsp;tamanhos mĂŠdios de famĂ­lia.<br /><b>#pgv_lang[stat_1_map]#</b>&nbsp;&nbsp;localizaĂ§ĂŁo de todas as pessoas ou pessoas com o nome especificado, por paĂ­s.<br /><b>#pgv_lang[stat_2_map]#</b>&nbsp;&nbsp;paĂ­s de nascimento.<br /><b>#pgv_lang[stat_4_map]#</b>&nbsp;&nbsp;paĂ­s de casamento.<br /><b>#pgv_lang[stat_3_map]#</b>&nbsp;&nbsp;paĂ­s da morte.<br /><b>#pgv_lang[stat_9_indi]#</b>&nbsp;&nbsp;diagrama de cĂ­rculo de indivĂ­duos com fontes.<br /><b>#pgv_lang[stat_8_fam]#</b>&nbsp;&nbsp;diagrama de cĂ­rculo de famĂ­lias com fontes.</p>";
$pgv_lang["stat_help_y"]			= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~EIXO Y~<br /><br />As seguintes opĂ§Ăľes estĂŁo disponĂ­veis para o eixo Y (vertical). Essas opĂ§Ăľes alteram a forma como os itens apresentados no eixo X sĂŁo exibidos.<p style=\"padding-left: 25px\"><b>#pgv_lang[stat_201_num]#</b>&nbsp;&nbsp;exibe o nĂşmero de pessoas em cada categoria definida pelo eixo X.<br /><b>#pgv_lang[stat_202_perc]#</b>&nbsp;&nbsp;calcula e exibe a proporĂ§ĂŁo de cada item nas categorias do eixo X.</p>";
$pgv_lang["stat_help_z"]			= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~EIXO Z~<br /><br />As seguintes opĂ§Ăľes estĂŁo disponĂ­veis para o eixo Z. Essas opĂ§Ăľes fornecem uma subdivisĂŁo das categorias selecionadas para o eixo X.<p style=\"padding-left: 25px\"><b>#pgv_lang[stat_300_none]#</b>&nbsp;&nbsp;exibe os itens como uma Ăşnica coluna para cada categoria do eixo X.<br /><b>#pgv_lang[stat_301_mf]#</b>&nbsp;&nbsp;exibe os itens em 2 colunas (masculino e feminino) para cada categoria do eixo X.<br /><b>#pgv_lang[stat_302_cgp]#</b>&nbsp;&nbsp;exibe os itens em vĂĄrias colunas relacionadas aos perĂ­odos de tempo definidos na prĂłxima seĂ§ĂŁo, para cada categoria do eixo X.</p>";
$pgv_lang["stat_help_gwx"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~limites para o eixo X~<br /><br />Selecione o intervalo de idade desejado.<br /><br />Por exemplo, <b>#pgv_lang[aft_marr]#</b> descreve o seguinte conjunto de intervalos de meses:<div style=\"padding-left: 30px;\">antes do casamento<br />desde o casamento atĂŠ 8 meses depois<br />de 8 a 12<br />de 12 a 15<br />de 15 a 18<br />de 18 a 24<br />de 24 a 48<br />mais de 48 meses apĂłs o casamento</div><br /><br />Quando vocĂŞ deseja mostrar os trimestres, vocĂŞ deve escolher: <b>trimestres</b>.";
$pgv_lang["stat_help_gax"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~limites para o eixo X~<br /><br />Selecione o intervalo de idade desejado.<br /><br />Por exemplo, <b>intervalo de 10 anos</b> descreve o seguinte conjunto de faixas etĂĄrias:<div style=\"padding-left: 30px;\">menor de um ano<br />um ano a 5 anos<br />6 a 10<br />11 a 20<br />21 a 30<br />31 a 40<br />41 a 50<br />51 a 60<br />61 a 70<br />71 a 80<br />81 a 90<br />91 a 100<br />mais de 100 anos</div>";
$pgv_lang["stat_help_gbx"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~limites para o eixo X~<br /><br />Selecione o intervalo de idade desejado.<br /><br />Por exemplo, <b>intervalo de 2 anos</b> descreve o seguinte conjunto de faixas etĂĄrias:<div style=\"padding-left: 30px;\">menor de 16 anos<br />16 a 18<br />19 a 20<br />21 a 22<br />23 a 24<br />25 a 26<br />27 a 28<br />29 a 30<br />31 a 32<br />33 a 35<br />36 a 40<br />41 a 50<br />mais de 50 anos</div>";
$pgv_lang["stat_help_gcx"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~limites para o eixo X~<br /><br />Selecione o intervalo de contagem desejado.<br /><br />Por exemplo, <b>intervalo um filho</b> descreve o seguinte conjunto de intervalos de contagem de filhos:<div style=\"padding-left: 30px;\">sem filhos<br />um filho<br />dois filhos<br />3, 4, 5, 6, 7, 8, 9, 10 filhos<br />mais de 10 filhos</div>";
$pgv_lang["stat_help_gwz"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />~limites para o eixo Z~<br /><br />Selecione o ano de inĂ­cio desejado e o intervalo<br /><br />Por exemplo, <b>de 1700 intervalo 50 anos</b> descreve o seguinte conjunto de intervalos de datas:<div style=\"padding-left: 30px;\">antes de 1700<br />1700 a 1749<br />1750 a 1799<br />1800 a 1849<br />1850 a 1899<br />1900 a 1949<br />1950 a 1999<br />2000 ou mais tarde</div>";
$pgv_lang["chart_type_help"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />Selecione o que vocĂŞ deseja ver no mapa. VocĂŞ pode escolher:<p style=\"padding-left: 25px\"><b>#pgv_lang[indi_distribution_chart]#</b>&nbsp;&nbsp;mostra os paĂ­ses em que ocorrem as pessoas desta base de dados.<br /><b>#pgv_lang[surname_distribution_chart]#</b>&nbsp;&nbsp;mostra os paĂ­ses nos quais o sobrenome especificado ocorre.</p>";
$pgv_lang["google_chart_surname_help"]	= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />O nĂşmero de ocorrĂŞncias do nome especificado serĂĄ mostrado no mapa. Se vocĂŞ deixar este campo em branco, o sobrenome mais comum serĂĄ usado.";
$pgv_lang["chart_area_help"]		= "~OPĂĂES PARA GRĂFICOS ESTATĂSTICOS~<br /><br />Selecione a ĂĄrea geogrĂĄfica que vocĂŞ deseja ver no mapa. VocĂŞ pode escolher:<p style=\"padding-left: 25px\"><b>#pgv_lang[world_chart]#</b>&nbsp;&nbsp;mostra todos os continentes.<br /><b>#pgv_lang[europe_chart]#</b>&nbsp;&nbsp;mostra a Europa.<br /><b>#pgv_lang[s_america_chart]#</b>&nbsp;&nbsp;mostra a AmĂŠrica do Sul.<br /><b>#pgv_lang[asia_chart]#</b>&nbsp;&nbsp;mostra a Ăsia.<br /><b>#pgv_lang[middle_east_chart]#</b>&nbsp;&nbsp;mostra o Oriente MĂŠdio.<br /><b>#pgv_lang[africa_chart]#</b>&nbsp;&nbsp;mostra a Ăfrica.</p>";

//-- Find Media Help
$pgv_lang["manage_media_help"]		= "~#pgv_lang[manage_media]#~<br /><br />Nesta pĂĄgina vocĂŞ pode gerenciar facilmente seus arquivos e diretĂłrios de mĂ­dia.<br /><br />Quando vocĂŞ cria novos subdiretĂłrios de mĂ­dia, PhpGedView irĂĄ garantir que a estrutura de diretĂłrio idĂŞntica seja mantida dentro do diretĂłrio <b>#GLOBALS[MEDIA_DIRECTORY]#thumbs</b>. Quando vocĂŞ carrega novos arquivos de mĂ­dia, PhpGedView pode criar automaticamente as miniaturas para vocĂŞ.<br /><br />Ao lado de cada imagem na lista de mĂ­dia, vocĂŞ encontrarĂĄ as seguintes opĂ§Ăľes. As opĂ§Ăľes realmente mostradas dependem do status atual do arquivo de mĂ­dia.<ul><li><b>#pgv_lang[edit]#</b>&nbsp;&nbsp;Ao clicar nesta opĂ§ĂŁo, vocĂŞ verĂĄ uma pĂĄgina onde pode alterar o tĂ­tulo do objeto MĂ­dia. Se o objeto MĂ­dia ainda nĂŁo estiver vinculado a uma pessoa, famĂ­lia ou fonte no banco de dados ativo no momento, vocĂŞ pode estabelecer esse vĂ­nculo aqui. VocĂŞ pode renomear o arquivo ou atĂŠ mesmo alterar sua localizaĂ§ĂŁo na estrutura de diretĂłrio <b>#GLOBALS[MEDIA_DIRECTORY]#</b>. Quando necessĂĄrio, PhpGedView criarĂĄ automaticamente os subdiretĂłrios necessĂĄrios ou quaisquer miniaturas ausentes.</li><li><b>#pgv_lang[edit_raw]#</b>&nbsp;&nbsp;Esta opĂ§ĂŁo estĂĄ disponĂ­vel apenas quando o administrador a habilita. VocĂŞ pode visualizar ou editar os dados GEDCOM brutos associados a este objeto MĂ­dia. VocĂŞ deve ter muito cuidado ao usar esta opĂ§ĂŁo.</li><li><b>#pgv_lang[delete_file]#</b>&nbsp;&nbsp;Esta opĂ§ĂŁo permite que vocĂŞ apague todo o conhecimento do arquivo de mĂ­dia do banco de dados atual. Outros bancos de dados nĂŁo serĂŁo afetados. Se este arquivo de mĂ­dia nĂŁo for mencionado em nenhum outro banco de dados, ele e sua miniatura associada serĂŁo excluĂ­dos.</li><li><b>#pgv_lang[remove_object]#</b>&nbsp;&nbsp;Esta opĂ§ĂŁo permite que vocĂŞ apague todo o conhecimento do arquivo de mĂ­dia do banco de dados atual. Outros bancos de dados nĂŁo serĂŁo afetados. O arquivo de mĂ­dia e sua miniatura associada nĂŁo serĂŁo excluĂ­dos.</li><li><b>#pgv_lang[remove_links]#</b>&nbsp;&nbsp;Esta opĂ§ĂŁo permite remover todos os links para o objeto de mĂ­dia do banco de dados atual. O arquivo nĂŁo serĂĄ excluĂ­do e o objeto MĂ­dia pelo qual este arquivo ĂŠ conhecido no banco de dados atual serĂĄ retido. Outros bancos de dados nĂŁo serĂŁo afetados.</li><li><b>#pgv_lang[set_link]#</b>&nbsp;&nbsp;Esta opĂ§ĂŁo permite estabelecer ligaĂ§Ăľes entre o arquivo de mĂ­dia e pessoas, famĂ­lias ou fontes do banco de dados atual. Quando necessĂĄrio, o PhpGedView tambĂŠm criarĂĄ o objeto Media pelo qual o arquivo Media ĂŠ conhecido no banco de dados.</li><li><b>#pgv_lang[gen_thumb]#</b>&nbsp;&nbsp;Ao selecionar esta opĂ§ĂŁo, PhpGedView criarĂĄ a miniatura ausente.</li></ul>";
$pgv_lang["simple_filter_help"]		= "~#pgv_lang[filter]#~<br /><br />Filtro de pesquisa simples, baseado nos caracteres informados, onde curingas nĂŁo sĂŁo aceitos.<br /><br />";
$pgv_lang["show_thumb_help"]		= "~#pgv_lang[show_thumbnail]#~<br /><br />Marque esta opĂ§ĂŁo para exibir as Miniaturas.<br /><br />";
$pgv_lang["find_media_help"]		= "~#pgv_lang[find_media]#~<br /><br />Isso permite que vocĂŞ pesquise a estrutura do arquivo para encontrar o item de mĂ­dia ao qual deseja vincular.";

//-- Add / Edit Media Help
$pgv_lang["add_media_linkid"]		= "~Link para o ID~<br /><br />Cada item de mĂ­dia deve estar associado a uma ou mais pessoas, famĂ­lia ou registros de origem em seu banco de dados.<br /><br /> Para estabelecer esse link, vocĂŞ pode inserir ou pesquisar a identidade da pessoa, famĂ­lia ou ao mesmo tempo em que cria o item de mĂ­dia. VocĂŞ tambĂŠm pode estabelecer o link posteriormente por meio das opĂ§Ăľes de ediĂ§ĂŁo na pĂĄgina Gerenciar MultimĂ­dia ou adicionando itens de mĂ­dia por meio do link Adicionar MĂ­dia disponĂ­vel na pĂĄgina de detalhes da Pessoa, FamĂ­lia ou Fonte.";
$pgv_lang["upload_server_file_help"] = "~#pgv_lang[server_file]#~<br /><br />O arquivo de mĂ­dia que vocĂŞ estĂĄ enviando pode ter, e provavelmente deveria ser, nomeado de maneira diferente no servidor e no computador local. Isso ocorre porque geralmente o nome do arquivo local tem significado para vocĂŞ, mas ĂŠ muito menos significativo para outras pessoas que visitam este site. Considere tambĂŠm a possibilidade de que vocĂŞ e outra pessoa tentem enviar arquivos diferentes chamados \"avozinha.jpg\".<br /><br />Neste campo, vocĂŞ especifica o novo nome do arquivo que estĂĄ enviando. O nome que vocĂŞ inserir aqui tambĂŠm serĂĄ usado para nomear a miniatura, que pode ser carregada separadamente ou gerada automaticamente. VocĂŞ nĂŁo precisa inserir a extensĂŁo do nome do arquivo (jpg, gif, pdf, doc, etc.)<br /><br />Deixe este campo em branco para manter o nome original do arquivo que vocĂŞ carregou de seu computador local.";
$pgv_lang["upload_server_folder_help"] = "~#pgv_lang[server_folder]#~<br /><br />O administrador habilitou atĂŠ #GLOBALS[MEDIA_DIRECTORY_LEVELS]# nĂ­veis de pasta abaixo do padrĂŁo <b>#GLOBALS[MEDIA_DIRECTORY]#</b>. Isso ajuda a organizar os arquivos de mĂ­dia e reduz a possibilidade de colisĂľes de nomes.<br /><br />Neste campo, vocĂŞ especifica a pasta de destino onde o arquivo de mĂ­dia carregado deve ser armazenado. O arquivo de miniatura correspondente, carregado separadamente ou gerado automaticamente, serĂĄ armazenado em uma estrutura de pasta semelhante comeĂ§ando em <b>#GLOBALS[MEDIA_DIRECTORY]#thumbs/</b> em vez de <b>#GLOBALS[MEDIA_DIRECTORY]#</b>. VocĂŞ nĂŁo precisa inserir a parte <b>#GLOBALS[MEDIA_DIRECTORY]#</b> do nome da pasta de destino.<br /><br />Se vocĂŞ nĂŁo tiver certeza sobre o que inserir aqui, entre em contato com o administrador do site para obter orientaĂ§ĂŁo.";
$pgv_lang["view_server_folder_help"] = "~#pgv_lang[server_folder]#~<br /><br />O administrador habilitou atĂŠ #GLOBALS[MEDIA_DIRECTORY_LEVELS]# nĂ­veis de pasta abaixo do padrĂŁo <b>#GLOBALS[MEDIA_DIRECTORY]#</b>. Isso ajuda a organizar os arquivos de mĂ­dia e reduz a possibilidade de colisĂľes de nomes.<br /><br /> Neste campo, vocĂŞ seleciona a pasta de mĂ­dia cujo conteĂşdo deseja visualizar. Quando vocĂŞ seleciona <b>#pgv_lang[all]#</b>, todos os arquivos de mĂ­dia sĂŁo exibidos independentemente da pasta na qual estĂŁo armazenados. Isso pode produzir uma lista muito longa de itens de mĂ­dia.";

//--Repository Help
$pgv_lang["help_repolist.php"]		= "~#pgv_lang[repo_list]#~<br /><br />Uma lista de repositĂłrios ĂŠ exibida nesta pĂĄgina.<br /><br />Os nomes dos repositĂłrios sĂŁo classificados em ordem alfabĂŠtica.<br /><br /><b>REPOSITĂRIOS</b><br />Sem repositĂłrios, nĂŁo podemos construir nosso banco de dados. Existe uma fonte para todas as informaĂ§Ăľes armazenadas no banco de dados, e essa fonte ĂŠ mantida em um repositĂłrio. Os repositĂłrios podem ser o arquivo pessoal de uma pessoa, uma instituiĂ§ĂŁo, um banco de dados pĂşblico, um escritĂłrio de registros do governo ou da igreja, um recurso da Internet, etc. Para obter acesso a uma fonte, queremos saber onde e em que lugar ela estĂĄ. Todas as informaĂ§Ăľes necessĂĄrias para encontrar uma fonte devem ser armazenadas no registro do RepositĂłrio.<br /><br />Um repositĂłrio pode ser vinculado a vĂĄrias fontes.";
$pgv_lang["help_repo.php"]			= "~#pgv_lang[repo_info]#~<br /><br />Os detalhes do RepositĂłrio sĂŁo exibidos aqui. Junto com as fontes, os repositĂłrios sĂŁo muito importantes para os pesquisadores genealĂłgicos. Com informaĂ§Ăľes precisas de origem e repositĂłrio, vocĂŞ pode seguir a trilha que outro pesquisador usou para encontrar as informaĂ§Ăľes. VocĂŞ deve conseguir encontrar as mesmas informaĂ§Ăľes novamente.<br /><br />Nesta pĂĄgina vocĂŞ pode ver informaĂ§Ăľes sobre o tĂ­tulo do RepositĂłrio, endereĂ§o, e-mail e pĂĄgina da web.<br /><br />ApĂłs os detalhes do repositĂłrio, serĂĄ uma lista de todas as fontes que estĂŁo vinculadas a este repositĂłrio. Isso permite que vocĂŞ veja todas as informaĂ§Ăľes obtidas de um repositĂłrio especĂ­fico.<br /><br />Se habilitado pelo administrador do site, vocĂŞ terĂĄ um ou mais dois Ă­cones de menu nesta pĂĄgina:<br /><b>#pgv_lang[view_gedcom]#</b>, que mostra as informaĂ§Ăľes em formato GEDCOM.<br /><b>#pgv_lang[add_to_cart]#</b>, que permite que vocĂŞ armazene essas informaĂ§Ăľes em seu #pgv_lang[clip_cart]#. De lĂĄ, vocĂŞ pode baixar as informaĂ§Ăľes em formato de arquivo GEDCOM e importĂĄ-las para seu prĂłprio programa de genealogia.<br /><br />#pgv_lang[context_help]#";
$pgv_lang["delete_repo_help"]			= "~#pgv_lang[delete_repo]#~<br /><br />Ao clicar nesta opĂ§ĂŁo, vocĂŞ marca este RepositĂłrio para ser excluĂ­do do banco de dados.<br /><br />O que isso significa?<br />Vamos supor que vocĂŞ tenha um bom motivo para remover este RepositĂłrio do banco de dados. VocĂŞ clica no link. VocĂŞ serĂĄ solicitado a confirmar sua solicitaĂ§ĂŁo de exclusĂŁo. Se vocĂŞ decidir continuar, pode demorar um pouco antes de ver uma mensagem de que o RepositĂłrio foi excluĂ­do.<br /><br />Ao continuar com sua visita, vocĂŞ notarĂĄ que o RepositĂłrio ainda estĂĄ visĂ­vel e pode ser usado como se a exclusĂŁo nĂŁo tivesse ocorrido.<br /><br /><b>Isso <u>nĂŁo</u> um erro.</b> O administrador do site receberĂĄ uma mensagem de que uma alteraĂ§ĂŁo foi feita ao banco de dados, e que vocĂŞ removeu o RepositĂłrio.<br />O administrador pode aceitar ou rejeitar sua alteraĂ§ĂŁo. Somente depois que o administrador aceitar sua alteraĂ§ĂŁo, a exclusĂŁo realmente ocorrerĂĄ <u>irreversivelmente</u>. Se houver alguma dĂşvida sobre a sua alteraĂ§ĂŁo, o administrador entrarĂĄ em contato com vocĂŞ.";
$pgv_lang["show_repo_gedcom_help"]	= "~#pgv_lang[view_gedcom]#~<br /><br />Ao clicar neste link, as informaĂ§Ăľes sobre o repositĂłrio, da forma como estĂĄ armazenado no banco de dados, serĂŁo exibidas em uma janela.";
$pgv_lang["add_repository_clip_help"]		= "~#pgv_lang[add_to_cart]#~<br /><br />Ao clicar neste link, vocĂŞ pode adicionar o repositĂłrio, como estĂĄ armazenado no banco de dados, ao seu #pgv_lang[clip_cart]#.";
$pgv_lang["repolist_listbox_help"]		= "~#pgv_lang[repo_list]#~<br /><br />Nesta caixa vocĂŞ vĂŞ os nomes dos repositĂłrios como eles sĂŁo armazenados no banco de dados.<br /><br /> Os nomes sĂŁo exibidos em ordem alfabĂŠtica.<br /><br />Ao clicar em um nome no lista, vocĂŞ irĂĄ para a pĂĄgina #pgv_lang[repo_info]#, onde verĂĄ uma lista das fontes que estĂŁo vinculadas a esse repositĂłrio.";
$pgv_lang["repos_listbox_help"]		= "~#pgv_lang[other_repo_records]#~<br /><br />Nesta caixa vocĂŞ vĂŞ os nomes das fontes que estĂŁo vinculadas ao repositĂłrio.<br /><br />Os nomes sĂŁo exibidos em ordem alfabĂŠtica.<br /><br />Ao clicar em um nome na lista, vocĂŞ irĂĄ para a pĂĄgina Detalhes dessa fonte.";

// Index-Edit
$pgv_lang["block_move_up_help"]		= "~Mover entradas da lista~<br /><br />Use esses botĂľes para reorganizar a ordem das entradas na lista. Os blocos serĂŁo impressos na ordem em que estĂŁo listados.<br /><br />Destaque a entrada a ser movida e clique em um botĂŁo para mover essa entrada para cima ou para baixo.";
$pgv_lang["block_move_right_help"]	= "~Mover entradas da lista~<br /><br />Use estes botĂľes para mover uma entrada de uma lista para outra.<br /><br />Destaque a entrada a ser movida e, a seguir, clique em um botĂŁo para mover ou copiar essa entrada na direĂ§ĂŁo da seta. Use os botĂľes <b>Âť</b> e <b>ÂŤ</b> para mover a entrada destacada da lista mais Ă  esquerda para a mais Ă  direita ou vice-versa. Use os botĂľes <b>&gt;</b> e <b>&lt;</b> para mover a entrada destacada entre a lista #pgv_lang[available_blocks]# e a lista para a direita ou esquerda.<br /><br />As entradas na lista #pgv_lang[available_blocks]# nĂŁo muda, independentemente do que vocĂŞ faz com os botĂľes #pgv_lang[move_right]# e #pgv_lang[move_left]#. Isso porque o mesmo bloco pode aparecer vĂĄrias vezes na mesma pĂĄgina. O bloco HTML ĂŠ um bom exemplo de por que vocĂŞ pode querer fazer isso.";
$pgv_lang["block_default_index"]	= "~Blocos padrĂŁo na pĂĄgina #pgv_lang[welcome]#~<br /><br />Quando vocĂŞ remove todas as entradas das listas #pgv_lang[main_section]# e #pgv_lang[right_section]#, ou quando vocĂŞ clica no botĂŁo <b>#pgv_lang[reset_default_blocks]#</b>, a lista de bloqueios serĂĄ configurada da seguinte forma:<br /><br /><span class='center'><table border=\"1\"><tr><td class=\"list_value\"><b>#pgv_lang[main_section]#</b></td><td class=\"list_value\"><b>#pgv_lang[right_section]#</b></td></tr><tr><td>#pgv_lang[block_cookiepolicy]#<br />#pgv_lang[gedcom_stats_block]#<br />#pgv_lang[gedcom_news_block]#<br />#pgv_lang[gedcom_favorites_block]#<br />#pgv_lang[review_changes_block]#</td><td>#pgv_lang[gedcom_block]#<br />#pgv_lang[random_media_block]#<br />#pgv_lang[todays_events_block]#<br />#pgv_lang[logged_in_users_block]#</td></tr></table></span>";
$pgv_lang["block_default_portal"]	= "~Blocos padrĂŁo na pĂĄgina #pgv_lang[mygedview]#~<br /><br />Quando vocĂŞ remove todas as entradas das listas #pgv_lang[main_section]# e #pgv_lang[right_section]#, ou quando vocĂŞ clica no botĂŁo <b>#pgv_lang[reset_default_blocks]#</b>, a lista de bloqueios serĂĄ configurada da seguinte forma:<br /><br /><span class='center'><table border=\"1\"><tr><td class=\"list_value\"><b>#pgv_lang[main_section]#</b></td><td class=\"list_value\"><b>#pgv_lang[right_section]#</b></td></tr><tr><td>#pgv_lang[todays_events_block]#<br />#pgv_lang[user_messages_block]#<br />#pgv_lang[user_favorites_block]#<br />&nbsp;</td><td>#pgv_lang[welcome_block]#<br />#pgv_lang[random_media_block]#<br />#pgv_lang[upcoming_events_block]#<br />#pgv_lang[logged_in_users_block]#</td></tr></table></span>";

